# ANTI-PATTERN: Monolithic, hard-coded preprocessing
class CricketBallClassifier_Bad:
    def preprocess(self, image):
        # All steps tangled together, hard to test/modify
        image = cv2.resize(image, (224, 224))
        image = image / 255.0
        image = image - np.array([0.485, 0.456, 0.406])
        image = image / np.array([0.229, 0.224, 0.225])
        # If you need different normalization, rewrite entire method
        return image

# BEST PRACTICE: Pipeline Pattern + Strategy Pattern
from abc import ABC, abstractmethod

class PreprocessStep(ABC):
    @abstractmethod
    def apply(self, image):
        pass

class ResizeStep(PreprocessStep):
    def __init__(self, size=(224, 224)):
        self.size = size
    def apply(self, image):
        return cv2.resize(image, self.size)

class NormalizeStep(PreprocessStep):
    def __init__(self, mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]):
        self.mean = np.array(mean)
        self.std = np.array(std)
    def apply(self, image):
        image = image / 255.0
        return (image - self.mean) / self.std

class PreprocessPipeline:
    def __init__(self, steps):
        self.steps = steps  # Compose steps flexibly
    def execute(self, image):
        for step in self.steps:
            image = step.apply(image)
        return image

# Usage: Easy to swap, test, and extend
pipeline = PreprocessPipeline([
    ResizeStep((224, 224)),
    NormalizeStep()  # Change normalization without touching ResizeStep
])

processed_ball_image = pipeline.execute(cricket_ball_img)
